/// </summary>
[ExtensionOf(classStr(SalesPackingSlipJournalCreate))]
final class SalesPackingSlipJournalCreate_ETGSPAIN_Class_Extension
{
}

Method.Source:
/// <summary>
/// Extension of the <c>initJournalLine</c> method.
/// </summary>
/// <param name="_parmLine">Parameter line.</param>
/// <returns>Returns a Common object.</returns>
public Common initJournalLine(Common _parmLine)
{
    CustPackingSlipTrans    custPackingSlipTrans    = next initJournalLine(_parmLine);

    if(CompanyInfo::find().ETGSpanishCompany == NoYes::Yes)
    {
        SalesParmLine           salesParmLine           = _parmLine as SalesParmLine;

        custPackingSlipTrans.ETGSPAINCustSalesReference          = salesParmLine.ETGSPAINCustSalesReference;
        custPackingSlipTrans.ETGSPAINInventLicensePlate          = salesParmLine.ETGSPAINInventLicensePlate;
        custPackingSlipTrans.ETGSPAINInventPackingSlipTransitId  = salesParmLine.ETGSPAINInventPackingSlipTransitId;
        custPackingSlipTrans.ETGSPAINSalesCustomerWithdrawalDate = salesParmLine.ETGSPAINSalesCustomerWithdrawalDate;

        custPackingSlipTrans.ETGSPAINUnsoldQtyModify            = salesParmLine.ETGSPAINUnsoldQtyModify;
    }

    return custPackingSlipTrans;
}
